INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r1", "The reporting organization shall identify its stakeholders, and explain how it has responded to their reasonable expectations and interests.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "ONE OR MORE", "GRI-101-1", "GRI-101-1-1", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r2", "The report shall present the reporting organization’s performance in the wider context of sustainability.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-1", "GRI-101-1-2", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r3", "The report shall cover topics that reflect the reporting organization’s significant economic, environmental, and social impacts.", NOW(), NOW(), NOW(), "TOPIC, IMPACT", "NaN", "ONE OR MORE", "GRI-101-1", "GRI-101-1-3", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r4", "The report shall cover topics that substantively influence the assessments and decisions of stakeholders.", NOW(), NOW(), NOW(), "TOPIC, STAKEHOLDER", "NaN", "ONE OR MORE", "GRI-101-1", "GRI-101-1-4", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r5", "The report shall include coverage of material topics and their Boundaries, sufficient to reflect significant economic, environmental, and social impacts, and to enable stakeholders to assess the reporting organization’s performance in the reporting period.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, BOUNDARY, IMPACT, STAKEHOLDER, REPORTING_PERIOD", "NaN", "ONE OR MORE", "GRI-101-1", "GRI-101-1-5", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r6", "The reported information shall be sufficiently accurate and detailed for stakeholders to assess the reporting organization’s performance.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "NaN", "GRI-101-1", "GRI-101-1-5", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r7", "The reported information shall reflect positive and negative aspects of the reporting organization’s performance to enable a reasoned assessment of overall performance.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-1", "GRI-101-1-6", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r8", "The reporting organization shall make information available in a manner that is understandable and accessible to stakeholders using that information.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "NaN", "GRI-101-1", "GRI-101-1-7", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r9", "The reporting organization shall select, compile, and report information consistently. The reported information shall be presented in a manner that enables stakeholders to analyze changes in the organization’s performance over time, and that could support analysis relative to other organizations.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "NaN", "GRI-101-1", "GRI-101-1-8", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r10", "The reporting organization shall report on a regular schedule so that information is available in time for stakeholders to make informed decisions.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "NaN", "GRI-101-1", "GRI-101-1-8", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r11", "The reporting organization shall apply all Reporting Principles from Section 1 to define report content and quality.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-2", "GRI-101-2-11", "GRI-101-r1,GRI-101-r2,GRI-101-r3,GRI-101-r4,GRI-101-r5,GRI-101-r6,GRI-101-r7,GRI-101-r8,GRI-101-r9,GRI-101-r10");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r12", "The reporting organization shall report the required disclosures from GRI 102: General Disclosures.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-2", "GRI-101-2-11", "GRI-102-r1,GRI-102-r2,GRI-102-r3,GRI-102-r4,GRI-102-r5,GRI-102-r6,GRI-102-r7,GRI-102-r8,GRI-102-r9,GRI-102-r10,GRI-102-r11,GRI-102-r12,GRI-102-r13,GRI-102-r14,GRI-102-r15,GRI-102-r16,GRI-102-r17,GRI-102-r18,GRI-102-r19,GRI-102-r20,GRI-102-r21,GRI-102-r22,GRI-102-r23,GRI-102-r24,GRI-102-r25,GRI-102-r26,GRI-102-r27,GRI-102-r28,GRI-102-r29,GRI-102-r30,GRI-102-r31,GRI-102-r32,GRI-102-r33,GRI-102-r34,GRI-102-r35,GRI-102-r36,GRI-102-r37,GRI-102-r38,GRI-102-r39,GRI-102-r40,GRI-102-r41,GRI-102-r42,GRI-102-r43,GRI-102-r44,GRI-102-r45,GRI-102-r46,GRI-102-r47,GRI-102-r48,GRI-102-r49,GRI-102-r50,GRI-102-r51,GRI-102-r52,GRI-102-r53,GRI-102-r54,GRI-102-r55,GRI-102-r56,GRI-102-r57,GRI-102-r58,GRI-102-r59,GRI-102-r60,GRI-102-r61,GRI-102-r62,GRI-102-r63,GRI-102-r64,GRI-102-r65,GRI-102-r66,GRI-102-r67,GRI-102-r68,GRI-102-r69,GRI-102-r70,GRI-102-r71,GRI-102-r72,GRI-102-r73,GRI-102-r74,GRI-102-r75,GRI-102-r76,GRI-102-r77");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r13", "The reporting organization shall identify its material topics using the Reporting Principles for defining report content.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC", "NaN", "ONE OR MORE", "GRI-101-2", "GRI-101-2-13", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r14", "The reporting organization shall identify its material topics using the Reporting Principles for defining report content.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, BOUNDARY", "NaN", "ONE OR MORE", "GRI-101-2", "GRI-101-2-13", "GRI-101-r13");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r15", "For each material topic, the reporting organization shall report the management approach disclosures for that topic, using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, BOUNDARY", "NaN", "ONE OR MORE", "GRI-101-2", "GRI-101-2-14", "GRI-101-r16_GRI-101-r17");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r16", "For each material topic, the reporting organization shall report the topic-specific disclosures in the corresponding GRI Standard, if the material topic is covered by an existing GRI Standard (series 200, 300, and 400)", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, BOUNDARY", "NaN", "ONE OR MORE", "GRI-101-2", "GRI-101-2-14", "GRI-101-r15");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r17", "For each material topic, the reporting organization should report other appropriate disclosures, if the material topic is not covered by an existing GRI Standard.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, BOUNDARY", "NaN", "ONE OR MORE", "GRI-101-2", "GRI-101-2-14", "GRI-101-r15");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r18", "If the reporting organization reports a required disclosure using a reference to another source where the information is located, the organization shall ensure the reference includes the specific location of the required disclosure.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-3", "GRI-101-2-15", "GRI-101-r19");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r19", "If the reporting organization reports a required disclosure using a reference to another source where the information is located, the organization shall ensure the referenced information is publicly available and readily accessible.", NOW(), NOW(), NOW(), "NaN", "NaN", "NaN", "GRI-101-3", "GRI-101-2-15", "GRI-101-r18");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r20", "To claim that a sustainability report has been prepared in accordance with the GRI Standards, the reporting organization shall meet all criteria for the respective option (Core or Comprehensive) from Table 1 (on page 23).", NOW(), NOW(), NOW(), "TABLE_1-GRI-101", "NaN", "MULTIPLE", "GRI-101-3", "GRI-101-3-16", "TABLE_1-GRI-101-r20");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r21", "If, in exceptional cases, an organization preparing a sustainability report in accordance with the GRI Standards cannot report a required disclosure, the organization shall provide in the report a reason for omission that describes the specific information that has been omitted.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE OR MORE", "GRI-101-3", "GRI-101-3-16", "GRI-101-r22");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r22", "If, in exceptional cases, an organization preparing a sustainability report in accordance with the GRI Standards cannot report a required disclosure, the organization shall provide in the report a reason for omission that specifies one of the following reasons for omission from Table 2, including the required explanation for that reason.", NOW(), NOW(), NOW(), "TABLE_2-GRI-101", "NaN", "ONE", "GRI-101-3", "GRI-101-3-16", "GRI-101-r21");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r23", "If the reporting organization uses selected GRI Standards, or parts of their content, to report specific information, but has not met the criteria to prepare a report in accordance with the GRI Standards (as per clause 3.1), the organization shall include in any published material with disclosures based on the GRI Standards a statement that contains the following text: ‘This material references [title and publication year of the Standard]’, for each Standard used and indicates which specific content from the Standard has been applied, if the Standard has not been used in full.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE", "GRI-101-3", "GRI-101-3-17", "GRI-101-r24,GRI-101-r25,GRI-101-r26,GRI-101-r27");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r24", "If the reporting organization uses selected GRI Standards, or parts of their content, to report specific information, but has not met the criteria to prepare a report in accordance with the GRI Standards (as per clause 3.1), the organization shall comply with all reporting requirements that correspond to the disclosures reported.", NOW(), NOW(), NOW(), "NaN", "NaN", "MULTIPLE", "GRI-101-3", "GRI-101-3-17", "GRI-101-r23,GRI-101-r25,GRI-101-r26,GRI-101-r27");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r25", "If the reporting organization uses selected GRI Standards, or parts of their content, to report specific information, but has not met the criteria to prepare a report in accordance with the GRI Standards (as per clause 3.1), the organization shall notify GRI of the use of the Standards, as per clause 3.4.", NOW(), NOW(), NOW(), "GRI-101-3-20", "NaN", "NaN", "GRI-101-3", "GRI-101-3-17", "GRI-101-r23,GRI-101-r24,GRI-101-r26,GRI-101-r27");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r26", "If the reporting organization uses selected GRI Standards, or parts of their content, to report specific information, but has not met the criteria to prepare a report in accordance with the GRI Standards (as per clause 3.1), the organization should apply the Reporting Principles for defining report quality from Section 1.", NOW(), NOW(), NOW(), "GRI-101-1-5,GRI-101-1-6,GRI-101-1-7,GRI-101-1-8,GRI-101-1-9,GRI-101-1-10", "NaN", "ONE OR MORE", "GRI-101-3", "GRI-101-3-17", "GRI-101-r23,GRI-101-r24,GRI-101-r25,GRI-101-r27");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r27", "If the reporting organization uses selected GRI Standards, or parts of their content, to report specific information, but has not met the criteria to prepare a report in accordance with the GRI Standards (as per clause 3.1), the organization should report its management approach by applying GRI 103: Management Approach together with any topic-specific Standard (series 200, 300, or 400) used.", NOW(), NOW(), NOW(), "GRI-103-1", "NaN", "ONE OR MORE", "GRI-101-3", "GRI-101-3-17", "GRI-101-r23,GRI-101-r24,GRI-101-r25,GRI-101-r26");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r28", "The reporting organization shall notify GRI of its use of the GRI Standards, and the claim it has made in the report or published material, by sending a copy to GRI at standards@globalreporting.org", NOW(), NOW(), NOW(), "MAIL_GLOBALREPORTING", "NaN", "ONE", "GRI-101-3", "GRI-101-3-18","_GRI-101-r29");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-101-r29", "The reporting organization shall notify GRI of its use of the GRI Standards, and the claim it has made in the report or published material, by registering the report or published material at www.globalreporting.org/standards.", NOW(), NOW(), NOW(), "URL_GLOBALREPORTING", "NaN", "ONE", "GRI-101-3", "GRI-101-3-18", "_GRI-101-r28");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r1", "The reporting organization shall report the following information: Name of the organization.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE", "GRI-102-1", "GRI-102-1-1", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r2", "The reporting organization shall report the following information: A description of the organization’s activities. b. Primary brands, products, and services, including an explanation of any products or services that are banned in certain markets.", NOW(), NOW(), NOW(), "PRODUCT, SERVICE", "NaN", "ONE", "GRI-102-1", "GRI-102-1-2", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r3", "The reporting organization shall report the following information: Location of the organization’s headquarters.", NOW(), NOW(), NOW(), "GEOLOCATION", "NaN", "ONE", "GRI-102-1", "GRI-102-1-3", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r4", "The reporting organization shall report the following information: Number of countries where the organization operates, and the names of countries where it has significant operations and/or that are relevant to the topics covered in the report.", NOW(), NOW(), NOW(), "LIST_OF_PLACES, TOPIC", "NaN", "ONE", "GRI-102-1", "GRI-102-1-4", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r5", "The reporting organization shall report the following information: Nature of ownership and legal form.", NOW(), NOW(), NOW(), "LEGAL_FORM", "NaN", "ONE", "GRI-102-1", "GRI-102-1-5", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r6", "The reporting organization shall report the following information: Markets served, including: i. geographic locations where products and services are offered; ii. sectors served; iii. types of customers and beneficiaries.", NOW(), NOW(), NOW(), "GEOLOCATION,LIST_OF_PLACES,PRODUCT,SERVICE,SECTOR", "NaN", "ONE", "GRI-102-1", "GRI-102-1-6", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r7", "The reporting organization shall report the following information: a. Scale of the organization, including: i. total number of employees; ii. total number of operations; iii. net sales (for private sector organizations) or net revenues (for public sector organizations); iv. total capitalization (for private sector organizations) broken down in terms of debt and equity; v. quantity of products or services provided.", NOW(), NOW(), NOW(), "EMPLOYEE,NET_SALES,NET_REVENUES,CAPITALIZATION,PRODUCT,SERVICE", "NaN", "ONE", "GRI-102-1", "GRI-102-1-7", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r8", "The reporting organization shall report the following information: a. Total number of employees by employment contract (permanent and temporary), by gender. b. Total number of employees by employment contract (permanent and temporary), by region. c. Total number of employees by employment type (full-time and part-time), by gender. d. Whether a significant portion of the organization’s activities are performed by workers who are not employees. If applicable, a description of the nature and scale of work performed by workers who are not employees. e. Any significant variations in the numbers reported in Disclosures a, b, and c (such as seasonal variations in the tourism or agricultural industries). f. An explanation of how the data have been compiled, including any assumptions made.", NOW(), NOW(), NOW(), "EMPLOYEE,EMPLOYMENT_CONTRACT,EMPLOYMENT_TYPE,WORKER,GENDER", "NaN", "ONE", "GRI-102-1", "GRI-102-1-8", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r9", "The reporting organization shall report the following information: a. A description of the organization’s supply chain, including its main elements as they relate to the organization’s activities, primary brands, products, and services.", NOW(), NOW(), NOW(), "SUPPLY_CHAIN, PRODUCT, SERVICE", "NaN", "ONE", "GRI-102-1", "GRI-102-1-9", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r10", "The reporting organization shall report the following information: a. Significant changes to the organization’s size, structure, ownership, or supply chain, including: i. Changes in the location of, or changes in, operations, including facility openings, closings, and expansions; ii. Changes in the share capital structure and other capital formation, maintenance, and alteration operations (for private sector organizations); iii. Changes in the location of suppliers, the structure of the supply chain, or relationships with suppliers, including selection and termination.", NOW(), NOW(), NOW(), "SUPPLY_CHAIN, SUPPLIER", "NaN", "DOCUMENT", "GRI-102-1", "GRI-102-1-10", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r11", "The reporting organization shall report the following information: a. Whether and how the organization applies the Precautionary Principle or approach.", NOW(), NOW(), NOW(), "PRECAUTIONARY_APPROACH", "NaN", "DOCUMENT", "GRI-102-1", "GRI-102-1-11", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r12", "The reporting organization shall report the following information: a. A list of externally-developed economic, environmental and social charters, principles, or other initiatives to which the organization subscribes, or which it endorses.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-1", "GRI-102-1-12", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r13", "The reporting organization shall report the following information: a. A list of the main memberships of industry or other associations, and national or international advocacy organizations.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE OR MORE", "GRI-102-1", "GRI-102-1-13", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r14", "The reporting organization shall report the following information: a. A statement from the most senior decision-maker of the organization (such as CEO, chair, or equivalent senior position) about the relevance of sustainability to the organization and its strategy for addressing sustainability. ", NOW(), NOW(), NOW(), "SUSTAINABILITY, REPORTING_PERIOD, PRODUCT, IMPACT, SUPPLIER, LOCAL_COMMUNITY, GRI-102-r14-REC", "NaN", "DOCUMENT", "GRI-102-2", "GRI-102-2-14", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r15", "The reporting organization shall report the following information: a. A description of key impacts, risks, and opportunities.", NOW(), NOW(), NOW(), "IMPACT, STAKEHOLDER, REPORTING_PERIOD, GRI-102-r15-REC", "NaN", "DOCUMENT", "GRI-102-2", "GRI-102-1-15", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r16", "The reporting organization shall report the following information: a. A description of the organization’s values, principles, standards, and norms of behavior.", NOW(), NOW(), NOW(), "WORKER, STAKEHOLDER, GRI-102-r16-REC", "NaN", "DOCUMENT", "GRI-102-3", "GRI-102-3-16", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r17", "The reporting organization shall report the following information: a. A description of internal and external mechanisms for: i. seeking advice about ethical and lawful behavior, and organizational integrity; ii. reporting concerns about unethical or unlawful behavior, and organizational integrity.", NOW(), NOW(), NOW(), "WORKER, STAKEHOLDER, REPORTING_PERIOD, GRI-102-r17-REC", "NaN", "ONE OR MORE", "GRI-102-3", "GRI-102-3-17", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r18", "The reporting organization shall report the following information: a. Governance structure of the organization, including committees of the highest governance body. b. Committees responsible for decision-making on economic, environmental, and social topics.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-18", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r19", "The reporting organization shall report the following information: a. Process for delegating authority for economic, environmental, and social topics from the highest governance body to senior executives and other employees.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-19", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r20", "The reporting organization shall report the following information: a. Whether the organization has appointed an executive-level position or positions with responsibility for economic, environmental, and social topics. b. Whether post holders report directly to the highest governance body.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-20", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r21", "The reporting organization shall report the following information: a. Processes for consultation between stakeholders and the highest governance body on economic, environmental, and social topics. b. If consultation is delegated, describe to whom it is delegated and how the resulting feedback is provided to the highest governance body.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-21", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r22", "The reporting organization shall report the following information: a. Process for delegating authority for economic, environmental, and social topics from the highest governance body to senior executives and other employees.", NOW(), NOW(), NOW(), "STAKEHOLDER, UNDER-REPRESENTED_SOCIAL_GROUP", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-22", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r23", "The reporting organization shall report the following information: a. Composition of the highest governance body and its committees by: i. executive or non-executive; ii. independence; iii. tenure on the governance body; iv. number of each individual’s other significant positions and commitments, and the nature of the commitments; v. gender; vi. membership of under-represented social groups; vii. competencies relating to economic, environmental, and social topics; viii. stakeholder representation.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-23", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r24", "The reporting organization shall report the following information: a. Nomination and selection processes for the highest governance body and its committees. b. Criteria used for nominating and selecting highest governance body members, including whether and how: i. stakeholders (including shareholders) are involved; ii. diversity is considered; iii. independence is considered; iv. expertise and experience relating to economic, environmental, and social topics are considered.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-24", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r25", "The reporting organization shall report the following information: a. Processes for the highest governance body to ensure conflicts of interest are avoided and managed. b. Whether conflicts of interest are disclosed to stakeholders, including, as a minimum: i. Cross-board membership; ii. Cross-shareholding with suppliers and other stakeholders; iii. Existence of controlling shareholder; iv. Related party disclosures.", NOW(), NOW(), NOW(), "STAKEHOLDER, CONFLICT_OF_INTEREST, SUPPLIER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-25", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r26", "The reporting organization shall report the following information: a. Highest governance body’s and senior executives’ roles in the development, approval, and updating of the organization’s purpose, value or mission statements, strategies, policies, and goals related to economic, environmental, and social topics.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-26", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r27", "The reporting organization shall report the following information: a. Measures taken to develop and enhance the highest governance body’s collective knowledge of economic, environmental, and social topics.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-27", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r28", "The reporting organization shall report the following information: a. Processes for evaluating the highest governance body’s performance with respect to governance of economic, environmental, and social topics. b. Whether such evaluation is independent or not, and its frequency. c. Whether such evaluation is a self-assessment. d. Actions taken in response to evaluation of the highest governance body’s performance with respect to governance of economic, environmental, and social topics, including, as a minimum, changes in membership and organizational practice.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-28", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r29", "The reporting organization shall report the following information: a. Highest governance body’s role in identifying and managing economic, environmental, and social topics and their impacts, risks, and opportunities – including its role in the implementation of due diligence processes. b. Whether stakeholder consultation is used to support the highest governance body’s identification and management of economic, environmental, and social topics and their impacts, risks, and opportunities.", NOW(), NOW(), NOW(), "IMPACT, DUE_DILIGENCE, STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-29", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r30", "The reporting organization shall report the following information: a. Highest governance body’s role in reviewing the effectiveness of the organization’s risk management processes for economic, environmental, and social topics.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-30", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r31", "The reporting organization shall report the following information: a. Frequency of the highest governance body’s review of economic, environmental, and social topics and their impacts, risks, and opportunities.", NOW(), NOW(), NOW(), "IMPACT", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-31", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r32", "The reporting organization shall report the following information: a. The highest committee or position that formally reviews and approves the organization’s sustainability report and ensures that all material topics are covered.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-32", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r33", "The reporting organization shall report the following information: a. Process for communicating critical concerns to the highest governance body.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-33", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r34", "The reporting organization shall report the following information: a. Total number and nature of critical concerns that were communicated to the highest governance body. b. Mechanism(s) used to address and resolve critical concerns.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-34", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r35", "The reporting organization shall report the following information: a. Remuneration policies for the highest governance body and senior executives for the following types of remuneration: i. Fixed pay and variable pay, including performance-based pay, equity-based pay, bonuses, and deferred or vested shares; ii. Sign-on bonuses or recruitment incentive payments; iii. Termination payments; iv. Clawbacks; v. Retirement benefits, including the difference between benefit schemes and contribution rates for the highest governance body, senior executives, and all other employees. b. How performance criteria in the remuneration policies relate to the highest governance body’s and senior executives’ objectives for economic, environmental, and social topics.", NOW(), NOW(), NOW(), "TERMINATION_PAYMENT, CLAWBACK, EMPLOYEE", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-35", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r36", "The reporting organization shall report the following information: a. Process for determining remuneration. b. Whether remuneration consultants are involved in determining remuneration and whether they are independent of management. c. Any other relationships that the remuneration consultants have with the organization.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-36", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r37", "The reporting organization shall report the following information: a. How stakeholders’ views are sought and taken into account regarding remuneration. b. If applicable, the results of votes on remuneration policies and proposals.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-37", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r38", "The reporting organization shall report the following information: a. Ratio of the annual total compensation for the organization’s highest-paid individual in each country of significant operations to the median annual total compensation for all employees (excluding the highest-paid individual) in the same country.", NOW(), NOW(), NOW(), "GRI-102-r38-REC, ANNUAL_TOTAL_COMPENSATION, EMPLOYMENT_TYPE, EMPLOYEE, REPORTING_PERIOD", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-38", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r39", "The reporting organization shall report the following information: a. Ratio of the percentage increase in annual total compensation for the organization’s highest-paid individual in each country of significant operations to the median percentage increase in annual total compensation for all employees (excluding the highest-paid individual) in the same country.", NOW(), NOW(), NOW(), "GRI-102-r39-REC, ANNUAL_TOTAL_COMPENSATION, EMPLOYEE, REPORTING_PERIOD", "NaN", "DOCUMENT", "GRI-102-4", "GRI-102-4-39", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r40", "The reporting organization shall report the following information: a. A list of stakeholder groups engaged by the organization. Examples of stakeholder groups are: civil society, customers, employees and workers who are not employees, trade unions, local communities, shareholders and providers of capital, suppliers", NOW(), NOW(), NOW(), "GRI-102-r39-REC, ANNUAL_TOTAL_COMPENSATION, EMPLOYEE, REPORTING_PERIOD", "NaN", "LIST_OF_TERMS", "GRI-102-5", "GRI-102-5-40", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r41", "The reporting organization shall report the following information: a. Percentage of total employees covered by collective bargaining agreements.", NOW(), NOW(), NOW(), "EMPLOYEE, COLLECTIVE_BARGAINING", "NaN", "DOCUMENT", "GRI-102-5", "GRI-102-5-41", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r42", "The reporting organization shall report the following information: a. The basis for identifying and selecting stakeholders with whom to engage.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-102-5", "GRI-102-5-42", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r43", "The reporting organization shall report the following information: a. The organization’s approach to stakeholder engagement, including frequency of engagement by type and by stakeholder group, and an indication of whether any of the engagement was undertaken specifically as part of the report preparation process.", NOW(), NOW(), NOW(), "GRI-102-r43-REC, STAKEHOLDER, SUPPLIER, WORKER, COLLECTIVE_BARGAINING", "NaN", "DOCUMENT", "GRI-102-5", "GRI-102-5-43", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r44", "The reporting organization shall report the following information: a. Key topics and concerns that have been raised through stakeholder engagement, including: i. how the organization has responded to those key topics and concerns, including through its reporting; ii. the stakeholder groups that raised each of the key topics and concerns.", NOW(), NOW(), NOW(), "STAKEHOLDER, REPORTING_PERIOD, PRODUCT_OR_SERVICE_CATEGORY", "NaN", "DOCUMENT", "GRI-102-5", "GRI-102-5-44", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r45", "The reporting organization shall report the following information: a. A list of all entities included in the organization’s consolidated financial statements or equivalent documents. b. Whether any entity included in the organization’s consolidated financial statements or equivalent documents is not covered by the report", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-5", "GRI-102-5-45", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r46", "The reporting organization shall report the following information: a. An explanation of the process for defining the report content and the topic Boundaries. b. An explanation of how the organization has implemented the Reporting Principles for defining report content.", NOW(), NOW(), NOW(), "TOPIC_BOUNDARY, REPORTING_PRINCIPLE, MATERIAL_TOPIC", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-46", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r47", "The reporting organization shall report the following information: a. A list of the material topics identified in the process for defining report content.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE OR MORE", "GRI-102-6", "GRI-102-6-47", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r48", "The reporting organization shall report the following information: a. The effect of any restatements of information given in previous reports, and the reasons for such restatements.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-48", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r49", "The reporting organization shall report the following information: a. Significant changes from previous reporting periods in the list of material topics and topic Boundaries.", NOW(), NOW(), NOW(), "REPORTING_PERIOD,MATERIAL_TOPIC,TOPIC_BOUNDARY", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-49", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r50", "The reporting organization shall report the following information: a. Reporting period for the information provided.", NOW(), NOW(), NOW(), "REPORTING_PERIOD", "NaN", "OME OR MORE", "GRI-102-6", "GRI-102-6-50", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r51", "The reporting organization shall report the following information: a. If applicable, the date of the most recent previous report.", NOW(), NOW(), NOW(), "NaN", "NaN", "ONE", "GRI-102-6", "GRI-102-6-51", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r52", "The reporting organization shall report the following information: a. Reporting cycle.", NOW(), NOW(), NOW(), "TIME_DURATION", "NaN", "ONE", "GRI-102-6", "GRI-102-6-52", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r53", "The reporting organization shall report the following information: a. The contact point for questions regarding the report or its contents.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-53", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r54", "The reporting organization shall report the following information: a. The claim made by the organization, if it has prepared a report in accordance with the GRI Standards, either: i. ‘This report has been prepared in accordance with the GRI Standards: Core option’; ii. ‘This report has been prepared in accordance with the GRI Standards: Comprehensive option’.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-54", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r55", "The reporting organization shall report the following information: a. The GRI content index, which specifies each of the GRI Standards used and lists all disclosures included in the report. b. For each disclosure, the content index shall include: i. the number of the disclosure (for disclosures covered by the GRI Standards); ii. the page number(s) or URL(s) where the information can be found, either within the report or in other published materials; iii. if applicable, and where permitted, the reason(s) for omission when a required disclosure cannot be made.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-55", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-102-r56", "The reporting organization shall report the following information: a. A description of the organization’s policy and current practice with regard to seeking external assurance for the report. b. If the report has been externally assured: i. A reference to the external assurance report, statements, or opinions. If not included in the assurance report accompanying the sustainability report, a description of what has and what has not been assured and on what basis, including the assurance standards used, the level of assurance obtained, and any limitations of the assurance process; ii. The relationship between the organization and the assurance provider; iii. Whether and how the highest governance body or senior executives are involved in seeking external assurance for the organization’s sustainability report.", NOW(), NOW(), NOW(), "HIGHEST_COVERNANCE_BODY, SENIOR_EXECUTIVES", "NaN", "DOCUMENT", "GRI-102-6", "GRI-102-6-56", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-103-r1", "If management approach disclosures are combined for a group of material topics, the reporting organization shall state which topics are covered by each disclosure. If there is no management approach for a material topic, the reporting organization shall describe any plans to implement a management approach or the reasons for not having a management approach.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, GRI-103-r1-REC", "NaN", "ONE OR MORE", "GRI-103-1", "GRI-103-1-0", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-103-r2", "For each material topic, the reporting organization shall report the following information: a. An explanation of why the topic is material. b. The Boundary for the material topic, which includes a description of: i. where the impacts occur; ii. the organization’s involvement with the impacts. For example, whether the organization has caused or contributed to the impacts, or is directly linked to the impacts through its business relationships. c. Any specific limitation regarding the topic Boundary.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, IMPACT, VALUE_CHAIN, DUE_DILIGENCE, TOPIC_BOUNDARY, GRI-103-r2-REC", "NaN", "ONE OR MORE", "GRI-103-1", "GRI-103-1-1", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-103-r3", "For each material topic, the reporting organization shall report the following information: a. An explanation of how the organization manages the topic. b. A statement of the purpose of the management approach. c. A description of the following, if the management approach includes that component: i. Policies ii. Commitments iii. Goals and targets iv. Responsibilities v. Resources vi. Grievance mechanisms vii. Specific actions, such as processes, projects, programs and initiatives", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, GRIEVANCE_MECHANISM", "NaN", "ONE OR MORE", "GRI-103-1", "GRI-103-1-2", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-103-r4", "For each material topic, the reporting organization shall report the following information: a. An explanation of how the organization evaluates the management approach, including: i. the mechanisms for evaluating the effectiveness of the management approach; ii. the results of the evaluation of the management approach; iii. any related adjustments to the management approach.", NOW(), NOW(), NOW(), "MATERIAL_TOPIC, GRI-103-r1-REC", "NaN", "ONE OR MORE", "GRI-103-1", "GRI-103-1-3", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-201-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-201-1", "GRI-201-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-201-r2", "The reporting organization shall report the following information: a. Direct economic value generated and distributed (EVG&D) on an accruals basis, including the basic components for the organization’s global operations as listed below. If data are presented on a cash basis, report the justification for this decision in addition to reporting the following basic components: i. Direct economic value generated: revenues; ii. Economic value distributed: operating costs, employee wages and benefits, payments to providers of capital, payments to government by country, and community investments; iii. Economic value retained: ‘direct economic value generated’ less ‘economic value distributed’. b. Where significant, report EVG&D separately at country, regional, or market levels, and the criteria used for defining significance..", NOW(), NOW(), NOW(), "EMPLOYEE, GRI-201-r2-REC", "NaN", "DOCUMENT", "GRI-201-2", "GRI-201-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-201-r4", "The reporting organization shall report the following information: a. Risks and opportunities posed by climate change that have the potential to generate substantive changes in operations, revenue, or expenditure, including: i. a description of the risk or opportunity and its classification as either physical, regulatory, or other; ii. a description of the impact associated with the risk or opportunity; iii. the financial implications of the risk or opportunity before action is taken; iv. the methods used to manage the risk or opportunity; v. the costs of actions taken to manage the risk or opportunity.", NOW(), NOW(), NOW(), "GRI-201-r3-REC", "NaN", "DOCUMENT", "GRI-201-2", "GRI-201-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-201-r4", "The reporting organization shall report the following information: a. If the plan’s liabilities are met by the organization’s general resources, the estimated value of those liabilities. b. If a separate fund exists to pay the plan’s pension liabilities: the extent to which the scheme’s liabilities are estimated to be covered by the assets that have been set aside to meet them; the basis on which that estimate has been arrived at; when that estimate was made. c. If a fund set up to pay the plan’s pension liabilities is not fully covered, explain the strategy, if any, adopted by the employer to work towards full coverage, and the timescale, if any, by which the employer hopes to achieve full coverage. d. Percentage of salary contributed by employee or employer. e. Level of participation in retirement plans, such as participation in mandatory or voluntary schemes, regional, or country-based schemes, or those with financial impact.", NOW(), NOW(), NOW(), "DEFINED_BENEFIT_PLAN, DEFINED_CONTRIBUTION_PLAN, FULL_COVERAGE, GRI-201-r4-REC", "NaN", "DOCUMENT", "GRI-201-2", "GRI-201-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-201-r5", "The reporting organization shall report the following information: a. Total monetary value of financial assistance received by the organization from any government during the reporting period, including: i. tax relief and tax credits; ii. subsidies; iii. investment grants, research and development grants, and other relevant types of grant; iv. awards; v. royalty holidays; vi. financial assistance from Export Credit Agencies (ECAs); vii. financial incentives; viii. other financial benefits received or receivable from any government for any operation. b. The information in 201-4-a by country. c. Whether, and the extent to which, any government is present in the shareholding structure.", NOW(), NOW(), NOW(), "FINANCIAL_ASSISTANCE, GRI-201-r5-REC", "NaN", "DOCUMENT", "GRI-201-2", "GRI-201-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-202-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-202-1", "GRI-202-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-202-r2", "The reporting organization shall report the following information: a. When a significant proportion of employees are compensated based on wages subject to minimum wage rules, report the relevant ratio of the entry level wage by gender at significant locations of operation to the minimum wage. b. When a significant proportion of other workers (excluding employees) performing the organization’s activities are compensated based on wages subject to minimum wage rules, describe the actions taken to determine whether these workers are paid above the minimum wage. c. Whether a local minimum wage is absent or variable at significant locations of operation, by gender. In circumstances in which different minimums can be used as a reference, report which minimum wage is being used. d. The definition used for ‘significant locations of operation’.", NOW(), NOW(), NOW(), "EMPLOYEE, WORKER, ENTRY_LEVEL_WAGE, LOCAL_MINIMUM_WAGE, GRI-202-r2-REC", "NaN", "DOCUMENT", "GRI-202-2", "GRI-202-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-202-r3", "The reporting organization shall report the following information: a. Percentage of senior management at significant locations of operation that are hired from the local community. b. The definition used for ‘senior management’. c. The organization’s geographical definition of ‘local’. d. The definition used for ‘significant locations of operation’.", NOW(), NOW(), NOW(), "EMPLOYEE, EMPLOYMENT_TYPE, GRI-202-r3-REC", "NaN", "DOCUMENT", "GRI-202-2", "GRI-202-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-203-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "INFRASTRUCTURE, GRI-203-r1-REC", "NaN", "DOCUMENT", "GRI-203-1", "GRI-203-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-203-r2", "The reporting organization shall report the following information: a. Extent of development of significant infrastructure investments and services supported. b. Current or expected impacts on communities and local economies, including positive and negative impacts where relevant. c. Whether these investments and services are commercial, in-kind, or pro bono engagements.", NOW(), NOW(), NOW(), "SERVICES_SUPPORTED, INFRASTRUCTURE, GRI-203-r2-REC", "NaN", "DOCUMENT", "GRI-203-2", "GRI-203-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-203-r3", "The reporting organization shall report the following information: a. Examples of significant identified indirect economic impacts of the organization, including positive and negative impacts. b. Significance of the indirect economic impacts in the context of external benchmarks and stakeholder priorities, such as national and international standards, protocols, and policy agendas.", NOW(), NOW(), NOW(), "SECTORS, GRI-203-r3-REC", "NaN", "DOCUMENT", "GRI-203-2", "GRI-203-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-204-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "GRI-204-r1-REC, SUPPLY_CHAIN, SUPPLIER, LOCAL_SUPPLIER", "NaN", "DOCUMENT", "GRI-204-1", "GRI-204-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-204-r2", "The reporting organization shall report the following information: a. Percentage of the procurement budget used for significant locations of operation that is spent on suppliers local to that operation (such as percentage of products and services purchased locally). b. The organization’s geographical definition of ‘local’. c. The definition used for ‘significant locations of operation’.", NOW(), NOW(), NOW(), "GRI-204-r2-REC", "NaN", "DOCUMENT", "GRI-204-2", "GRI-202-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-205-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "NaN", "NaN", "DOCUMENT", "GRI-205-1", "GRI-205-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-205-r2", "The reporting organization shall report the following information: a. Total number and percentage of operations assessed for risks related to corruption. b. Significant risks related to corruption identified through the risk assessment.", NOW(), NOW(), NOW(), "CORRUPTION, GRI-205-r2-REC", "NaN", "DOCUMENT", "GRI-205-2", "GRI-205-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-205-r3", "The reporting organization shall report the following information: a. Total number and percentage of governance body members that the organization’s anti-corruption policies and procedures have been communicated to, broken down by region. b. Total number and percentage of employees that the organization’s anti-corruption policies and procedures have been communicated to, broken down by employee category and region. c. Total number and percentage of business partners that the organization’s anti-corruption policies and procedures have been communicated to, broken down by type of business partner and region. Describe if the organization’s anti-corruption policies and procedures have been communicated to any other persons or organizations. d. Total number and percentage of governance body members that have received training on anti-corruption, broken down by region. e. Total number and percentage of employees that have received training on anti-corruption, broken down by employee category and region.", NOW(), NOW(), NOW(), "CORRUPTION, EMPLOYEE_CATEGORY, EMPLOYEE", "NaN", "DOCUMENT", "GRI-205-2", "GRI-205-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-205-r4", "The reporting organization shall report the following information: a. Total number and nature of confirmed incidents of corruption. b. Total number of confirmed incidents in which employees were dismissed or disciplined for corruption. c. Total number of confirmed incidents when contracts with business partners were terminated or not renewed due to violations related to corruption. d. Public legal cases regarding corruption brought against the organization or its employees during the reporting period and the outcomes of such cases.", NOW(), NOW(), NOW(), "CORRUPTION, EMPLOYEE, EMPLOYEE_CATEGORY", "NaN", "DOCUMENT", "GRI-205-2", "GRI-205-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-206-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-206-1", "GRI-206-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-206-r2", "The reporting organization shall report the following information: a. Number of legal actions pending or completed during the reporting period regarding anti-competitive behavior and violations of anti-trust and monopoly legislation in which the organization has been identified as a participant. b. Main outcomes of completed legal actions, including any decisions or judgments.", NOW(), NOW(), NOW(), "ANTI_COMPETITIVE_BEHAVIOR, ANTI_TRUST_AND_MONOPOLY_PRACTICE", "NaN", "DOCUMENT", "GRI-206-2", "GRI-206-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-207-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-207-1", "GRI-207-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-207-r2", "The reporting organization shall report the following information: a. A description of the approach to tax, including: i. whether the organization has a tax strategy and, if so, a link to this strategy if publicly available; ii. the governance body or executive-level position within the organization that formally reviews and approves the tax strategy, and the frequency of this review; iii. the approach to regulatory compliance; iv. how the approach to tax is linked to the business and sustainable development strategies of the organization.", NOW(), NOW(), NOW(), "SUSTAINABLE_DEVELOPMENT, GOVERNANCE_BODY", "NaN", "DOCUMENT", "GRI-207-1", "GRI-207-1-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-207-r3", "The reporting organization shall report the following information: a. A description of the tax governance and control framework, including: i. the governance body or executive-level position within the organization accountable for compliance with the tax strategy; ii. how the approach to tax is embedded within the organization; iii. the approach to tax risks, including how risks are identified, managed, and monitored; iv. how compliance with the tax governance and control framework is evaluated. b. A description of the mechanisms for reporting concerns about unethical or unlawful behavior and the organization’s integrity in relation to tax. c. A description of the assurance process for disclosures on tax and, if applicable, a reference to the assurance report, statement, or opinion.", NOW(), NOW(), NOW(), "GOVERNANCE_BODY", "NaN", "DOCUMENT", "GRI-207-1", "GRI-207-1-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-207-r4", "The reporting organization shall report the following information: a. A description of the approach to stakeholder engagement and management of stakeholder concerns related to tax, including: i. the approach to engagement with tax authorities; ii. the approach to public policy advocacy on tax; iii. the processes for collecting and considering the views and concerns of stakeholders, including external stakeholders.", NOW(), NOW(), NOW(), "STAKEHOLDER", "NaN", "DOCUMENT", "GRI-207-1", "GRI-207-1-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-207-r5", "The reporting organization shall report the following information: a. All tax jurisdictions where the entities included in the organization’s audited consolidated financial statements, or in the financial information filed on public record, are resident for tax purposes. b. For each tax jurisdiction reported: i. Names of the resident entities; ii. Primary activities of the organization; iii. Number of employees, and the basis of calculation of this number; iv. Revenues from third-party sales; v. Revenues from intra-group transactions with other tax jurisdictions; vi. Profit/loss before tax; vii. Tangible assets other than cash and cash equivalents; viii. Corporate income tax paid on a cash basis; ix. Corporate income tax accrued on profit/loss; x. Reasons for the difference between corporate income tax accrued on profit/loss and the tax due if the statutory tax rate is applied to profit/loss before tax. c. The time period covered by the information reported in Disclosure 207-4.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-207-2", "GRI-207-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-301-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-301-1", "GRI-301-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-301-r2", "The reporting organization shall report the following information: a. Total weight or volume of materials that are used to produce and package the organization’s primary products and services during the reporting period, by: i. non-renewable materials used; ii. renewable materials used.", NOW(), NOW(), NOW(), "GRI-301-r2-REC, NON_RENEWABLE_MATERIALS, RENEWABLE_MATERIALS", "NaN", "DOCUMENT", "GRI-301-2", "GRI-301-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-301-r3", "The reporting organization shall report the following information: a. Percentage of recycled input materials used to manufacture the organization’s primary products and services.", NOW(), NOW(), NOW(), "RECYCLED_INPUT_MATERIAL, TOTAL_RECYCLED_INPUT_MATERIALS_USED, TOTAL_INPUT_MATERIALS_USED, GRI-301-r3-REC", "NaN", "DOCUMENT", "GRI-301-2", "GRI-301-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-301-r4", "The reporting organization shall report the following information: a. Percentage of reclaimed products and their packaging materials for each product category. b. How the data for this disclosure have been collected.", NOW(), NOW(), NOW(), "RECLAIMED, PRODUCT_CATEGORY, GRI-301-r4-REC", "NaN", "DOCUMENT", "GRI-301-2", "GRI-301-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-301-1", "GRI-301-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r2", "The reporting organization shall report the following information: a. Total fuel consumption within the organization from non-renewable sources, in joules or multiples, and including fuel types used. b. Total fuel consumption within the organization from renewable sources, in joules or multiples, and including fuel types used. c. In joules, watt-hours or multiples, the total: electricity consumption; heating consumption; cooling consumption; steam consumption d. In joules, watt-hours or multiples, the total: electricity sold; heating sold; cooling sold; steam sold e. Total energy consumption within the organization, in joules or multiples. f. Standards, methodologies, assumptions, and/or calculation tools used. g. Source of the conversion factors used.", NOW(), NOW(), NOW(), "NON_RENEWABLE_ENERGY_SOURCE, RENEWABLE_ENERGY_SOURCE, TOTAL_ENERGY_CONSUMPTION, TOTAL_FUEL_CONSUMPTION, TOTAL_ELECTRICITY_CONSUMPTION, TOTAL_COOLING_CONSUMPTION, TOTAL_HEATING_CONSUMPTION, TOTAL_STEAM_CONSUMPTION, TOTAL_ELECTRICITY_SOLD, TOTAL_COOLING_SOLD, TOTAL_HEATING_SOLD, TOTAL_STEAM_SOLD", "NaN", "DOCUMENT", "GRI-302-2", "GRI-302-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r3", "The reporting organization shall report the following information: a. Energy consumption outside of the organization, in joules or multiples. b. Standards, methodologies, assumptions, and/or calculation tools used. c. Source of the conversion factors used.", NOW(), NOW(), NOW(), "EXTERNAL_ENERGY_CONSUMPTION", "NaN", "DOCUMENT", "GRI-302-2", "GRI-302-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r4", "The reporting organization shall report the following information: a. Energy intensity ratio for the organization. b. Organization-specific metric (the denominator) chosen to calculate the ratio. c. Types of energy included in the intensity ratio; whether fuel, electricity, heating, cooling, steam, or all. d. Whether the ratio uses energy consumption within the organization, outside of it, or both.", NOW(), NOW(), NOW(), "GRI-302-r4-REC", "NaN", "DOCUMENT", "GRI-302-2", "GRI-302-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r5", "The reporting organization shall report the following information: a. Amount of reductions in energy consumption achieved as a direct result of conservation and efficiency initiatives, in joules or multiples. b. Types of energy included in the reductions; whether fuel, electricity, heating, cooling, steam, or all. c. Basis for calculating reductions in energy consumption, such as base year or baseline, including the rationale for choosing it. d. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "ENERGY_REDUCTION, IMPACT, CONSERVATION_AND_EFFICIENCY_INITIATIVE, BASELINE, BASE_YEAR", "NaN", "DOCUMENT", "GRI-302-2", "GRI-302-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-302-r5", "The reporting organization shall report the following information: a. Reductions in energy requirements of sold products and services achieved during the reporting period, in joules or multiples. b. Basis for calculating reductions in energy consumption, such as base year or baseline, including the rationale for choosing it. c. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "ENERGY_REDUCTION, BASELINE, BASE_YEAR", "NaN", "DOCUMENT", "GRI-302-2", "GRI-302-2-5", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-303-1", "GRI-303-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303-r2", "The reporting organization shall report the following information: a. Total volume of water withdrawn, with a breakdown by the following sources: i. Surface water, including water from wetlands, rivers, lakes, and oceans; ii. Ground water; iii. Rainwater collected directly and stored by the organization; iv. Waste water from another organization; v. Municipal water supplies or other public or private water utilities. b. Standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "TOTAL_VOLUME_OF_WATER_WITHDRAWN", "NaN", "DOCUMENT", "GRI-303-2", "GRI-303-2-1", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303-r3", "The reporting organization shall report the following information: a. Total number of water sources significantly affected by withdrawal by type: i. Size of the water source; ii. Whether the source is designated as a nationally or internationally protected area; iii. Biodiversity value (such as species diversity and endemism, and total number of protected species); iv. Value or importance of the water source to local communities and indigenous peoples. b. Standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "WATER_SOURCE_SIZE, LOCAL_COMMUNITY, INDIGENOUS_PEOPLES", "NaN", "DOCUMENT", "GRI-303-2", "GRI-303-2-2", "NaN");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303-r4", "The reporting organization shall report the following information: a. Total volume of water recycled and reused by the organization. b. Total volume of water recycled and reused as a percentage of the total water withdrawal as specified in Disclosure 303-1. c. Standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "WATER_RECYCLING_AND_REUSE, TOTAL_WATER_WITHDRAWAL", "NaN", "DOCUMENT", "GRI-303-2", "GRI-303-2-3", "GRI-303-r2");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-303b-1", "GRI-303b-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r2", "The reporting organization shall report the following information: a. A description of how the organization interacts with water, including how and where water is withdrawn, consumed, and discharged, and the water-related impacts caused or contributed to, or directly linked to the organization’s activities, products or services by a business relationship (e.g., impacts caused by runoff). b. A description of the approach used to identify water-related impacts, including the scope of assessments, their timeframe, and any tools or methodologies used. c. A description of how water-related impacts are addressed, including how the organization works with stakeholders to steward water as a shared resource, and how it engages with suppliers or customers with significant water-related impacts. d. An explanation of the process for setting any water-related goals and targets that are part of the organization’s management approach, and how they relate to public policy and the local context of each area with water stress.", NOW(), NOW(), NOW(), "PRODUCT, SERVICE, STAKEHOLDER, SUPPLIER, IMPACT, WATER_STRESS, WATER_STEWARDSHIP, RUNOFF, WATER_DISCHARGE, WATER_WITHDRAWN, WATER_CONSUMED", "NaN", "DOCUMENT", "GRI-303b-1", "GRI-303b-1-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r3", "The reporting organization shall report the following information: a. A description of any minimum standards set for the quality of effluent discharge, and how these minimum standards were determined, including: i. how standards for facilities operating in locations with no local discharge requirements were determined; ii. any internally developed water quality standards or guidelines; iii. any sector-specific standards considered iv. whether the profile of the receiving waterbody was considered.", NOW(), NOW(), NOW(), "EFFLUENT", "NaN", "DOCUMENT", "GRI-303b-1", "GRI-303b-1-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r4", "The reporting organization shall report the following information: a. Total water withdrawal from all areas in megaliters, and a breakdown of this total by the following sources, if applicable: Surface water; Groundwater; Seawater; Produced water; Third-party water. b. Total water withdrawal from all areas with water stress in megaliters, and a breakdown of this total by the following sources, if applicable: Surface water; Groundwater; Seawater; Produced water; Third-party water, and a breakdown of this total by the withdrawal sources listed in i-iv. c. A breakdown of total water withdrawal from each of the sources listed in Disclosures 303-3-a and 303-3-b in megaliters by the following categories: Freshwater (≤1,000 mg/L Total Dissolved Solids); Other water (>1,000 mg/L Total Dissolved Solids). d. Any contextual information necessary to understand how the data have been compiled, such as any standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "SURFACE_WATER, GROUNDWATER, SEAWATER, PRODUCED_WATER, THIRD_PARTY_WATER, WATER_WITHDRAWN, WATER_STRESS", "NaN", "DOCUMENT", "GRI-303b-2", "GRI-303b-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r5", "The reporting organization shall report the following information: a. Total water discharge to all areas in megaliters, and a breakdown of this total by the following types of destination, if applicable: Surface water; Groundwater; Seawater; Third-party water, and the volume of this total sent for use to other organizations, if applicable. b. A breakdown of total water discharge to all areas in megaliters by the following categories: Freshwater (≤1,000 mg/L Total Dissolved Solids); Other water (>1,000 mg/L Total Dissolved Solids). c. Total water discharge to all areas with water stress in megaliters, and a breakdown of this total by the following categories: Freshwater (≤1,000 mg/L Total Dissolved Solids); Other water (>1,000 mg/L Total Dissolved Solids). d. Priority substances of concern for which discharges are treated, including: how priority substances of concern were defined, and any international standard, authoritative list, or criteria used; the approach for setting discharge limits for priority substances of concern; number of incidents of non-compliance with discharge limits. e. Any contextual information necessary to understand how the data have been compiled, such as any standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-303b-2", "GRI-303b-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-303b-r6", "The reporting organization shall report the following information: a. Total water consumption from all areas in megaliters. b. Total water consumption from all areas with water stress in megaliters. c. Change in water storage in megaliters, if water storage has been identified as having a significant water-related impact. d. Any contextual information necessary to understand how the data have been compiled, such as any standards, methodologies, and assumptions used, including whether the information is calculated, estimated, modeled, or sourced from direct measurements, and the approach taken for this, such as the use of any sector-specific factors.", NOW(), NOW(), NOW(), "WATER_CONSUMED, WATER_STRESS, WATER_STORAGE, IMPACT", "NaN", "DOCUMENT", "GRI-303b-2", "GRI-303b-2-5", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-304-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-304-1", "GRI-304-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-304-r2", "The reporting organization shall report the following information: a. For each operational site owned, leased, managed in, or adjacent to, protected areas and areas of high biodiversity value outside protected areas, the following information: i. Geographic location; ii. Subsurface and underground land that may be owned, leased, or managed by the organization; iii. Position in relation to the protected area (in the area, adjacent to, or containing portions of the protected area) or the high biodiversity value area outside protected areas; iv. Type of operation (office, manufacturing or production, or extractive); v. Size of operational site in km2 (or another unit, if appropriate); vi. Biodiversity value characterized by the attribute of the protected area or area of high biodiversity value outside the protected area (terrestrial, freshwater, or maritime ecosystem); vii. Biodiversity value characterized by listing of protected status (such as IUCN Protected Area Management Categories, Ramsar Convention, national legislation).", NOW(), NOW(), NOW(), "PROTECTED_AREAS, AREAS_OF_HIGH_BIODIVERSITY_VALUE", "NaN", "DOCUMENT", "GRI-304-2", "GRI-304-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-304-r3", "The reporting organization shall report the following information: a. Nature of significant direct and indirect impacts on biodiversity with reference to one or more of the following: Construction or use of manufacturing plants, mines, and transport infrastructure; Pollution (introduction of substances that do not naturally occur in the habitat from point and non-point sources); Introduction of invasive species, pests, and pathogens; Reduction of species; Habitat conversion; Changes in ecological processes outside the natural range of variation (such as salinity or changes in groundwater level). b. Significant direct and indirect positive and negative impacts with reference to the following: Species affected; Extent of areas impacted; Duration of impacts; Reversibility or irreversibility of the impacts.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-304-2", "GRI-304-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-304-r4", "The reporting organization shall report the following information: a. Size and location of all habitat areas protected or restored, and whether the success of the restoration measure was or is approved by independent external professionals. b. Whether partnerships exist with third parties to protect or restore habitat areas distinct from where the organization has overseen and implemented restoration or protection measures. c. Status of each area based on its condition at the close of the reporting period. d. Standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "AREA_PROTECTED, AREA_RESTORED", "NaN", "DOCUMENT", "GRI-304-2", "GRI-304-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-304-r5", "The reporting organization shall report the following information: a. Total number of International Union for Conservation of Nature (IUCN) Red List species and national conservation list species with habitats in areas affected by the operations of the organization, by level of extinction risk: i. Critically endangered ii. Endangered iii. Vulnerable iv. Near threatened v. Least concern", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-304-2", "GRI-304-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-305-1", "GRI-305-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r2", "The reporting organization shall report the following information: a. Gross direct (Scope 1) GHG emissions in metric tons of CO2 equivalent. b. Gases included in the calculation; whether CO2, CH4, N2O, HFCs, PFCs, SF6, NF3, or all. c. Biogenic CO2 emissions in metric tons of CO2 equivalent. d. Base year for the calculation, if applicable, including: the rationale for choosing it; emissions in the base year; the context for any significant changes in emissions that triggered recalculations of base year emissions. e. Source of the emission factors and the global warming potential (GWP) rates used, or a reference to the GWP source. f. Consolidation approach for emissions; whether equity share, financial control, or operational control. g. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "CARBON_DIOXIDE_EQUIVALENT, BIOGENIC_CARBON_DIOXIDE_EMISSIONS, GLOBAL_WARMING_POTENTIAL, DIRECT_SCOPE_1_CHG_EMISSIONS", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r3", "The reporting organization shall report the following information: a. Gross location-based energy indirect (Scope 2) GHG emissions in metric tons of CO2 equivalent. b. If applicable, gross market-based energy indirect (Scope 2) GHG emissions in metric tons of CO2 equivalent. c. If available, the gases included in the calculation; whether CO2, CH4, N2O, HFCs, PFCs, SF6, NF3, or all. d. Base year for the calculation, if applicable, including: the rationale for choosing it; emissions in the base year; the context for any significant changes in emissions that triggered recalculations of base year emissions. e. Source of the emission factors and the global warming potential (GWP) rates used, or a reference to the GWP source. f. Consolidation approach for emissions; whether equity share, financial control or operational control. g. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "BASE_YEAR, GLOBAL_WARMING_POTENTIAL, INDIRECT_SCOPE_2_CHG_EMISSIONS, CARBON_DIOXIDE_EQUIVALENT", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r4", "The reporting organization shall report the following information: a. Gross other indirect (Scope 3) GHG emissions in metric tons of CO2 equivalent. b. If available, the gases included in the calculation; whether CO2, CH4, N2O, HFCs, PFCs, SF6, NF3, or all. c. Biogenic CO2 emissions in metric tons of CO2 equivalent. d. Other indirect (Scope 3) GHG emissions categories and activities included in the calculation. e. Base year for the calculation, if applicable, including: the rationale for choosing it; emissions in the base year; the context for any significant changes in emissions that triggered recalculations of base year emissions. f. Source of the emission factors and the global warming potential (GWP) rates used, or a reference to the GWP source. g. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "OTHER_INDIRECT_SCOPE_3_CHG_EMISSIONS, BIOGENIC_CARBON_DIOXIDE_EMISSIONS, BASE_YEAR, GLOBAL_WARMING_POTENTIAL, CARBON_DIOXIDE_EQUIVALENT", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r5", "The reporting organization shall report the following information: a. GHG emissions intensity ratio for the organization. b. Organization-specific metric (the denominator) chosen to calculate the ratio. c. Types of GHG emissions included in the intensity ratio; whether direct (Scope 1), energy indirect (Scope 2), and/or other indirect (Scope 3). d. Gases included in the calculation; whether CO2, CH4, N2O, HFCs, PFCs, SF6, NF3, or all.", NOW(), NOW(), NOW(), "DIRECT_SCOPE_1_CHG_EMISSIONS, INDIRECT_SCOPE_2_CHG_EMISSIONS, OTHER_INDIRECT_SCOPE_3_CHG_EMISSIONS", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r6", "The reporting organization shall report the following information: a. GHG emissions reduced as a direct result of reduction initiatives, in metric tons of CO2 equivalent. b. Gases included in the calculation; whether CO2, CH4, N2O, HFCs, PFCs, SF6, NF3, or all. c. Base year or baseline, including the rationale for choosing it. d. Scopes in which reductions took place; whether direct (Scope 1), energy indirect (Scope 2), and/or other indirect (Scope 3). e. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "CARBON_DIOXIDE_EQUIVALENT, BASE_YEAR, BASELINE, DIRECT_SCOPE_1_CHG_EMISSIONS, INDIRECT_SCOPE_2_CHG_EMISSIONS, OTHER_INDIRECT_SCOPE_3_CHG_EMISSIONS", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-5", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r7", "The reporting organization shall report the following information: a. Production, imports, and exports of ODS in metric tons of CFC-11 (trichlorofluoromethane) equivalent. b. Substances included in the calculation. c. Source of the emission factors used. d. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "ODS, CFC_11_TRICHLOROFLUOROMETHANE", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-6", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-305-r8", "The reporting organization shall report the following information: a. Significant air emissions, in kilograms or multiples, for each of the following: NOX; SOX; Persistent organic pollutants (POP); Volatile organic compounds (VOC); Hazardous air pollutants (HAP); Particulate matter (PM); Other standard categories of air emissions identified in relevant regulations b. Source of the emission factors used. c. Standards, methodologies, assumptions, and/or calculation tools used.", NOW(), NOW(), NOW(), "SIGNIFICANT_AIR_EMISSIONS", "NaN", "DOCUMENT", "GRI-305-2", "GRI-305-2-7", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-306-1", "GRI-306-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r2", "The reporting organization shall report the following information: a. For the organization’s significant actual and potential waste-related impacts, a description of: i. the inputs, activities, and outputs that lead or could lead to these impacts; ii. whether these impacts relate to waste generated in the organization’s own activities or to waste generated upstream or downstream in its value chain.", NOW(), NOW(), NOW(), "WASTE, IMPACT, VALUE_CHAIN", "NaN", "DOCUMENT", "GRI-306-1", "GRI-306-1-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r3", "The reporting organization shall report the following information: a. Actions, including circularity measures, taken to prevent waste generation in the organization’s own activities and upstream and downstream in its value chain, and to manage significant impacts from waste generated. b. If the waste generated by the organization in its own activities is managed by a third party, a description of the processes used to determine whether the third party manages the waste in line with contractual or legislative obligations. c. The processes used to collect and monitor waste-related data.", NOW(), NOW(), NOW(), "WASTE, IMPACT, VALUE_CHAIN, CIRCULARITY_MEASURE", "NaN", "DOCUMENT", "GRI-306-1", "GRI-306-1-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r4", "The reporting organization shall report the following information: a. Total weight of waste generated in metric tons, and a breakdown of this total by composition of the waste. b. Contextual information necessary to understand the data and how the data has been compiled.", NOW(), NOW(), NOW(), "WASTE", "NaN", "DOCUMENT", "GRI-306-2", "GRI-306-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r5", "The reporting organization shall report the following information: a. Total weight of waste diverted from disposal in metric tons, and a breakdown of this total by composition of the waste. b. Total weight of hazardous waste diverted from disposal in metric tons, and a breakdown of this total by the following recovery operations: Preparation for reuse; Recycling; Other recovery operations. c. Total weight of non-hazardous waste diverted from disposal in metric tons, and a breakdown of this total by the following recovery operations: Preparation for reuse; Recycling; Other recovery operations. d. For each recovery operation listed in Disclosures 306-4-b and 306-4-c, a breakdown of the total weight in metric tons of hazardous waste and of non-hazardous waste diverted from disposal:  onsite; offsite. e. Contextual information necessary to understand the data and how the data has been compiled.", NOW(), NOW(), NOW(), "WASTE, PREPARATION_FOR_REUSE, RECYCLING, RECOVERY, DISPOSAL", "NaN", "DOCUMENT", "GRI-306-2", "GRI-306-2-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-306-r6", "The reporting organization shall report the following information: a. Total weight of waste directed to disposal in metric tons, and a breakdown of this total by composition of the waste. b. Total weight of hazardous waste directed to disposal in metric tons, and a breakdown of this total by the following disposal operations: Incineration (with energy recovery); Incineration (without energy recovery); Landfilling; Other disposal operations. c. Total weight of non-hazardous waste directed to disposal in metric tons, and a breakdown of this total by the following disposal operations: Incineration (with energy recovery); Incineration (without energy recovery); Landfilling; Other disposal operations. d. For each disposal operation listed in Disclosures 306-5-b and 306-5-c, a breakdown of the total weight in metric tons of hazardous waste and of non-hazardous waste directed to disposal: onsite; offsite. e. Contextual information necessary to understand the data and how the data has been compiled.", NOW(), NOW(), NOW(), "WASTE, DISPOSAL, HAZARDOUS_WASTE, INCINERATION, LANDFILLING", "NaN", "DOCUMENT", "GRI-306-2", "GRI-306-2-5", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-307-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-307-1", "GRI-307-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-307-r2", "The reporting organization shall report the following information: a. Significant fines and non-monetary sanctions for non-compliance with environmental laws and/or regulations in terms of: total monetary value of significant fines; total number of non-monetary sanctions; cases brought through dispute resolution mechanisms. b. If the organization has not identified any non-compliance with environmental laws and/or regulations, a brief statement of this fact is sufficient.", NOW(), NOW(), NOW(), "ENVIRONMENTAL_LAWS_AND_REGULATIONS", "NaN", "DOCUMENT", "GRI-307-2", "GRI-307-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-308-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-308-1", "GRI-308-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-308-r2", "The reporting organization shall report the following information: a. Percentage of new suppliers that were screened using environmental criteria.", NOW(), NOW(), NOW(), "SUPPLIER, SUPPLIER_SCREENING", "NaN", "DOCUMENT", "GRI-308-2", "GRI-308-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-308-r3", "The reporting organization shall report the following information: a. Number of suppliers assessed for environmental impacts. b. Number of suppliers identified as having significant actual and potential negative environmental impacts. c. Significant actual and potential negative environmental impacts identified in the supply chain. d. Percentage of suppliers identified as having significant actual and potential negative environmental impacts with which improvements were agreed upon as a result of assessment. e. Percentage of suppliers identified as having significant actual and potential negative environmental impacts with which relationships were terminated as a result of assessment, and why.", NOW(), NOW(), NOW(), "SUPPLIER, SUPPLY_CHAIN", "NaN", "DOCUMENT", "GRI-308-2", "GRI-308-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-401-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-401-1", "GRI-401-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-401-r2", "The reporting organization shall report the following information: a. Total number and rate of new employee hires during the reporting period, by age group, gender and region. b. Total number and rate of employee turnover during the reporting period, by age group, gender and region.", NOW(), NOW(), NOW(), "EMPLOYEE, EMPLOYEE_TURNOVER", "NaN", "DOCUMENT", "GRI-401-2", "GRI-401-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-401-r3", "The reporting organization shall report the following information: a. Benefits which are standard for full-time employees of the organization but are not provided to temporary or part-time employees, by significant locations of operation. These include, as a minimum: life insurance; health care; disability and invalidity coverage; parental leave; retirement provision; stock ownership; others. b. The definition used for ‘significant locations of operation’.", NOW(), NOW(), NOW(), "STANDARD_BENEFITS, PARENTAL_LEAVE, EMPLOYEE", "NaN", "DOCUMENT", "GRI-401-2", "GRI-401-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-401-r4", "The reporting organization shall report the following information: a. Total number of employees that were entitled to parental leave, by gender. b. Total number of employees that took parental leave, by gender. c. Total number of employees that returned to work in the reporting period after parental leave ended, by gender. d. Total number of employees that returned to work after parental leave ended that were still employed 12 months after their return to work, by gender. e. Return to work and retention rates of employees that took parental leave, by gender.", NOW(), NOW(), NOW(), "EMPLOYEE, PARENTAL_LEAVE", "NaN", "DOCUMENT", "GRI-401-2", "GRI-401-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-402-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-402-1", "GRI-402-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-402-r2", "The reporting organization shall report the following information: a. Minimum number of weeks’ notice typically provided to employees and their representatives prior to the implementation of significant operational changes that could substantially affect them. b. For organizations with collective bargaining agreements, report whether the notice period and provisions for consultation and negotiation are specified in collective agreements.", NOW(), NOW(), NOW(), "SIGNIFICANT_OPERATIONAL_CHANGE, COLLECTIVE_BARGAINING", "NaN", "DOCUMENT", "GRI-402-2", "GRI-402-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r2", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. A statement of whether an occupational health and safety management system has been implemented, including whether: the system has been implemented because of legal requirements and, if so, a list of the requirements; the system has been implemented based on recognized risk management and/or management system standards/guidelines and, if so, a list of the standards/guidelines. b. A description of the scope of workers, activities, and workplaces covered by the occupational health and safety management system, and an explanation of whether and, if so, why any workers, activities, or workplaces are not covered.", NOW(), NOW(), NOW(), "OCCUPATIONAL_HEALTH_AND_SAFETY_MANAGEMENT_SYSTEM", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r3", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. A description of the processes used to identify work-related hazards and assess risks on a routine and non-routine basis, and to apply the hierarchy of controls in order to hazards and minimize risks, including: how the organization ensures the quality of these processes, including the competency of persons who carry them out; how the results of these processes are used to evaluate and continually improve the occupational health and safety management system. b. A description of the processes for workers to report work-related hazards and hazardous situations, and an explanation of how workers are protected against reprisals. c. A description of the policies and processes for workers to remove themselves from work situations that they believe could cause injury or ill health, and an explanation of how workers are protected against reprisals. d. A description of the processes used to investigate work-related incidents, including the processes to identify hazards and assess risks relating to the incidents, to determine corrective actions using the hierarchy of controls, and to determine improvements needed in the occupational health and safety management system.", NOW(), NOW(), NOW(), "WORK_RELATED_HAZARD, OCCUPATIONAL_HEALTH_AND_SAFETY_RISK, HIERARCHY_OF_CONTROL, OCCUPATIONAL_HEALTH_AND_SAFETY_MANAGEMENT_SYSTEM, WORK_RELATED_INCIDENT", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r4", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. A description of the occupational health services’ functions that contribute to the identification and elimination of hazards and minimization of risks, and an explanation of how the organization ensures the quality of these services and facilitates workers’ access to them.", NOW(), NOW(), NOW(), "OCCUPATIONAL_HEALTH_SERVICE, WORK_RELATED_HAZARD, OCCUPATIONAL_HEALTH_AND_SAFETY_RISK", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r5", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. A description of the processes for worker participation and consultation in the development, implementation, and evaluation of the occupational health and safety management system, and for providing access to and communicating relevant information on occupational health and safety to workers. b. Where formal joint management–worker health and safety committees exist, a description of their responsibilities, meeting frequency, decision-making authority, and whether and, if so, why any workers are not represented by these committees.", NOW(), NOW(), NOW(), "WORKER_PARTICIPATION, WORKER_CONSULTATION, OCCUPATIONAL_HEALTH_AND_SAFETY_MANAGEMENT_SYSTEM, FORMAL_JOINT_MANAGEMENT_WORKER_HEALTH_AND_SAFETY_COMMITTEE", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-4", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r6", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. A description of any occupational health and safety training provided to workers, including generic training as well as training on specific work-related hazards, hazardous activities, or hazardous situations.", NOW(), NOW(), NOW(), "WORK_RELATED_HAZARD", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-5", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r7", "The reporting organization shall report the following information for employees and for workers who are not employees but whose work and/or workplace is controlled by the organization: a. An explanation of how the organization facilitates workers’ access to non-occupational medical and healthcare services, and the scope of access provided. b. A description of any voluntary health promotion services and programs offered to workers to address major non-work-related health risks, including the specific health risks addressed, and how the organization facilitates workers’ access to these services and programs.", NOW(), NOW(), NOW(), "HEALTH_PROMOTION", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-6", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r8", "The reporting organization shall report the following information: a. A description of the organization’s approach to preventing or mitigating significant negative occupational health and safety impacts that are directly linked to its operations, products or services by its business relationships, and the related hazards and risks.", NOW(), NOW(), NOW(), "PRODUCT, SERVICE, OCCUPATIONAL_HEALTH_AND_SAFETY_RISK, WORK_RELATED_HAZARD, OCCUPATIONAL_HEALTH_AND_SAFETY_RISK", "NaN", "DOCUMENT", "GRI-403-1", "GRI-403-1-7", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r9", "The reporting organization shall report the following information: a. If the organization has implemented an occupational health and safety management system based on legal requirements and/or recognized standards/guidelines: the number and percentage of all employees and workers who are not employees but whose work and/or workplace is controlled by the organization, who are covered by such a system; the number and percentage of all employees and workers who are not employees but whose work and/or workplace is controlled by the organization, who are covered by such a system that has been internally audited; the number and percentage of all employees and workers who are not employees but whose work and/or workplace is controlled by the organization, who are covered by such a system that has been audited or certified by an external party. b. Whether and, if so, why any workers have been excluded from this disclosure, including the types of worker excluded. c. Any contextual information necessary to understand how the data have been compiled, such a any standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "OCCUPATIONAL_HEALTH_AND_SAFETY_MANAGEMENT_SYSTEM", "NaN", "DOCUMENT", "GRI-403-2", "GRI-403-2-8", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r10", "The reporting organization shall report the following information: a. For all employees: The number and rate of fatalities as a result of work-related injury; The number and rate of high-consequence work-related injuries (excluding fatalities); The number and rate of recordable work-related injuries; The main types of work-related injury; The number of hours worked. b. For all workers who are not employees but whose work and/or workplace is controlled by the organization: The number and rate of fatalities as a result of work-related injury; The number and rate of high-consequence work-related injuries (excluding fatalities); The number and rate of recordable work-related injuries; The main types of work-related injury; The number of hours worked. c. The work-related hazards that pose a risk of high-consequence injury, including: how these hazards have been determined; which of these hazards have caused or contributed to high-consequence injuries during the reporting period; actions taken or underway to eliminate these hazards and minimize risks using the hierarchy of controls. d. Any actions taken or underway to eliminate other work-related hazards and minimize risks using the hierarchy of controls. e. Whether the rates have been calculated based on 200,000 or 1,000,000 hours worked. f. Whether and, if so, why any workers have been excluded from this disclosure, including the types of worker excluded. g. Any contextual information necessary to understand how the data have been compiled, such as any standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "EMPLOYEE, WORK_RELATED_INJURY, HIGH_CONSEQUENCE_WORK_RELATED_INJURY, RECORDABLE_WORK_RELATED_INJURY, WORK_RELATED_HAZARD, HIERARCHY_OF_CONTROL", "NaN", "DOCUMENT", "GRI-403-2", "GRI-403-2-9", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-403-r11", "The reporting organization shall report the following information: a. For all employees: The number of fatalities as a result of work-related ill health; The number of cases of recordable work-related ill health; The main types of work-related ill health. b. For all workers who are not employees but whose work and/or workplace is controlled by the organization: The number of fatalities as a result of work-related ill health; The number of cases of recordable work-related ill health; The main types of work-related ill health. c. The work-related hazards that pose a risk of ill health, including: how these hazards have been determined; which of these hazards have caused or contributed to cases of ill health during the reporting period; actions taken or underway to eliminate these hazards and minimize risks using the hierarchy of controls. d. Whether and, if so, why any workers have been excluded from this disclosure, including the types of worker excluded. e. Any contextual information necessary to understand how the data have been compiled, such as any standards, methodologies, and assumptions used.", NOW(), NOW(), NOW(), "EMPLOYEE, WORK_RELATED_ILL_HEALTH, RECORDABLE_WORK_RELATED_ILL_HEALTH, WORK_RELATED_HAZARD, OCCUPATIONAL_HEALTH_AND_SAFETY_RISK, HIERARCHY_OF_CONTROL", "NaN", "DOCUMENT", "GRI-403-2", "GRI-403-2-10", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-404-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-404-1", "GRI-404-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-404-r2", "The reporting organization shall report the following information: a. Average hours of training that the organization’s employees have undertaken during the reporting period, by: i. gender; ii. employee category.", NOW(), NOW(), NOW(), "GENDER, EMPLOYEE_CATEGORY", "NaN", "DOCUMENT", "GRI-404-2", "GRI-404-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-404-r3", "The reporting organization shall report the following information: a. Type and scope of programs implemented and assistance provided to upgrade employee skills. b. Transition assistance programs provided to facilitate continued employability and the management of career endings resulting from retirement or termination of employment.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-404-2", "GRI-404-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-404-r4", "The reporting organization shall report the following information: a. Percentage of total employees by gender and by employee category who received a regular performance and career development review during the reporting period.", NOW(), NOW(), NOW(), "EMPLOYEE, EMPLOYEE_CATEGORY, REGULAR_PERFORMANCE_AND_CAREER_DEVELOPMENT_REVIEW", "NaN", "DOCUMENT", "GRI-404-2", "GRI-404-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-405-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-405-1", "GRI-405-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-405-r2", "The reporting organization shall report the following information: a. Percentage of individuals within the organization’s governance bodies in each of the following diversity categories: Gender; Age group: under 30 years old, 30-50 years old, over 50 years old; Other indicators of diversity where relevant (such as minority or vulnerable groups). b. Percentage of employees per employee category in each of the following diversity categories: Gender; Age group: under 30 years old, 30-50 years old, over 50 years old; Other indicators of diversity where relevant (such as minority or vulnerable groups).", NOW(), NOW(), NOW(), "GOVERNANCE_BODY, INDICATOR_OF_DIVERSITY, VULNERABLE_GROUP, EMPLOYEE, EMPLOYEE_CATEGORY", "NaN", "DOCUMENT", "GRI-405-2", "GRI-405-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-405-r3", "The reporting organization shall report the following information: a. Ratio of the basic salary and remuneration of women to men for each employee category, by significant locations of operation. b. The definition used for ‘significant locations of operation’.", NOW(), NOW(), NOW(), "BASIC_SALARY, REMUNERATION, EMPLOYEE_CATEGORY", "NaN", "DOCUMENT", "GRI-405-2", "GRI-405-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-406-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-406-1", "GRI-406-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-406-r2", "The reporting organization shall report the following information: a. Total number of incidents of discrimination during the reporting period. b. Status of the incidents and actions taken with reference to the following: Incident reviewed by the organization; Remediation plans being implemented; Remediation plans that have been implemented, with results reviewed through routine internal management review processes; Incident no longer subject to action.", NOW(), NOW(), NOW(), "DISCRIMINATION", "NaN", "DOCUMENT", "GRI-406-2", "GRI-406-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-407-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-407-1", "GRI-407-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-407-r2", "The reporting organization shall report the following information: a. Operations and suppliers in which workers’ rights to exercise freedom of association or collective bargaining may be violated or at significant risk either in terms of: type of operation (such as manufacturing plant) and supplier; countries or geographic areas with operations and suppliers considered at risk. b. Measures taken by the organization in the reporting period intended to support rights to exercise freedom of association and collective bargaining.", NOW(), NOW(), NOW(), "SUPPLIER, WORKER, FREEDOM_OF_ASSOCIATION, COLLECTIVE_BARGAINING", "NaN", "DOCUMENT", "GRI-407-2", "GRI-407-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-408-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-408-1", "GRI-408-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-408-r2", "The reporting organization shall report the following information: a. Operations and suppliers considered to have significant risk for incidents of: child labor; young workers exposed to hazardous work. b. Operations and suppliers considered to have significant risk for incidents of child labor either in terms of: type of operation (such as manufacturing plant) and supplier; countries or geographic areas with operations and suppliers considered at risk. c. Measures taken by the organization in the reporting period intended to contribute to the effective abolition of child labor.", NOW(), NOW(), NOW(), "SUPPLIER, CHILD", "NaN", "DOCUMENT", "GRI-408-2", "GRI-408-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-409-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-409-1", "GRI-409-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-409-r2", "The reporting organization shall report the following information:a. Operations and suppliers considered to have significant risk for incidents of forced or compulsory labor either in terms of: type of operation (such as manufacturing plant) and supplier; countries or geographic areas with operations and suppliers considered at risk.b. Measures taken by the organization in the reporting period intended to contribute to the elimination of all forms of forced or compulsory labor.", NOW(), NOW(), NOW(), "SUPPLIER, FORCED_OR_COMPULSORY_LABOR", "NaN", "DOCUMENT", "GRI-409-2", "GRI-409-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-410-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-410-1", "GRI-410-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-410-r2", "The reporting organization shall report the following information: a. Percentage of security personnel who have received formal training in the organization’s human rights policies or specific procedures and their application to security. b. Whether training requirements also apply to third-party organizations providing security personnel.", NOW(), NOW(), NOW(), "SECURITY_PERSONNEL", "NaN", "DOCUMENT", "GRI-410-2", "GRI-410-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-411-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-411-1", "GRI-411-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-411-r2", "The reporting organization shall report the following information: a. Total number of identified incidents of violations involving the rights of indigenous peoples during the reporting period. b. Status of the incidents and actions taken with reference to the following: Incident reviewed by the organization; Remediation plans being implemented; Remediation plans that have been implemented, with results reviewed through routine internal management review processes; Incident no longer subject to action.", NOW(), NOW(), NOW(), "INDIGENOUS_PEOPLES", "NaN", "DOCUMENT", "GRI-411-2", "GRI-411-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-412-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-412-1", "GRI-412-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-412-r2", "The reporting organization shall report the following information: a. Total number and percentage of operations that have been subject to human rights reviews or human rights impact assessments, by country.", NOW(), NOW(), NOW(), "HUMAN_RIGHTS_REVIEWS", "NaN", "DOCUMENT", "GRI-412-2", "GRI-412-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-412-r3", "The reporting organization shall report the following information: a. Total number of hours in the reporting period devoted to training on human rights policies or procedures concerning aspects of human rights that are relevant to operations. b. Percentage of employees trained during the reporting period in human rights policies or procedures concerning aspects of human rights that are relevant to operations.", NOW(), NOW(), NOW(), "EMPLOYEE", "NaN", "DOCUMENT", "GRI-412-2", "GRI-412-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-412-r4", "The reporting organization shall report the following information: a. Total number and percentage of significant investment agreements and contracts that include human rights clauses or that underwent human rights screening. b. The definition used for ‘significant investment agreements’.", NOW(), NOW(), NOW(), "HUMAN_RIGHTS_CLAUSES", "NaN", "DOCUMENT", "GRI-412-2", "GRI-412-2-3", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-413-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-413-1", "GRI-413-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-413-r2", "The reporting organization shall report the following information: a. Percentage of operations with implemented local community engagement, impact assessments, and/or development programs, including the use of: social impact assessments, including gender impact assessments, based on participatory processes; environmental impact assessments and ongoing monitoring; public disclosure of results of environmental and social impact assessments; local community development programs based on local communities’ needs; stakeholder engagement plans based on stakeholder mapping; broad based local community consultation committees and processes that include vulnerable groups; works councils, occupational health and safety committees and other worker representation bodies to deal with impacts; formal local community grievance processes.", NOW(), NOW(), NOW(), "LOCAL_COMMUNITY, COMMUNITY_DEVELOPMENT_PROGRAME, VULNERABLE_GROUP", "NaN", "DOCUMENT", "GRI-413-2", "GRI-413-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-413-r3", "The reporting organization shall report the following information:a. Operations with significant actual and potential negative impacts on local communities, including: the location of the operations; the significant actual and potential negative impacts of operations.", NOW(), NOW(), NOW(), "COMMUNITY_OPERATION", "NaN", "DOCUMENT", "GRI-413-2", "GRI-413-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-414-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-414-1", "GRI-414-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-414-r2", "The reporting organization shall report the following information: a. Percentage of new suppliers that were screened using social criteria.", NOW(), NOW(), NOW(), "SUPPLIER, SUPPLIER_SCREENING", "NaN", "DOCUMENT", "GRI-414-2", "GRI-414-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-414-r3", "The reporting organization shall report the following information: a. Number of suppliers assessed for social impacts. b. Number of suppliers identified as having significant actual and potential negative social impacts. c. Significant actual and potential negative social impacts identified in the supply chain. d. Percentage of suppliers identified as having significant actual and potential negative social impacts with which improvements were agreed upon as a result of assessment. e. Percentage of suppliers identified as having significant actual and potential negative social impacts with which relationships were terminated as a result of assessment, and why.", NOW(), NOW(), NOW(), "SUPPLIER, SUPPLY_CHAIN", "NaN", "DOCUMENT", "GRI-414-2", "GRI-414-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-415-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-415-1", "GRI-415-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-415-r2", "The reporting organization shall report the following information: a. Total monetary value of financial and in-kind political contributions made directly and indirectly by the organization by country and recipient/beneficiary. b. If applicable, how the monetary value of in-kind contributions was estimated.", NOW(), NOW(), NOW(), "POLITICAL_CONTRIBUTION, INDIRECT_POLITICAL_CONTRIBUTION", "NaN", "DOCUMENT", "GRI-415-2", "GRI-415-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-416-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-416-1", "GRI-416-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-416-r2", "The reporting organization shall report the following information: a. Percentage of significant product and service categories for which health and safety impacts are assessed for improvement.", NOW(), NOW(), NOW(), "PRODUCT_OR_SERVICE_CATEGORY", "NaN", "DOCUMENT", "GRI-416-2", "GRI-416-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-416-r3", "The reporting organization shall report the following information: a. Total number of incidents of non-compliance with regulations and/or voluntary codes concerning the health and safety impacts of products and services within the reporting period, by: incidents of non-compliance with regulations resulting in a fine or penalty; incidents of non-compliance with regulations resulting in a warning; incidents of non-compliance with voluntary codes. b. If the organization has not identified any non-compliance with regulations and/or voluntary codes, a brief statement of this fact is sufficient.", NOW(), NOW(), NOW(), "PRODUCT, SERVICE, REPORTING_PERIOD", "NaN", "DOCUMENT", "GRI-416-2", "GRI-416-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-417-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-417-1", "GRI-417-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-417-r2", "The reporting organization shall report the following information:a. Whether each of the following types of information is required by the organization’s procedures for product and service information and labeling: The sourcing of components of the product or service; Content, particularly with regard to substances that might produce an environmental or social impact; Safe use of the product or service; Disposal of the product and environmental or social impacts; Other (explain). b. Percentage of significant product or service categories covered by and assessed for compliance with such procedures.", NOW(), NOW(), NOW(), "PRODUCT_AND_SERVICE_INFORMATION_AND_LABELING", "NaN", "DOCUMENT", "GRI-417-2", "GRI-417-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-417-r3", "The reporting organization shall report the following information: a. Total number of incidents of non-compliance with regulations and/or voluntary codes concerning marketing communications, including advertising, promotion, and sponsorship, by: incidents of non-compliance with regulations resulting in a fine or penalty; incidents of non-compliance with regulations resulting in a warning; incidents of non-compliance with voluntary codes. b. If the organization has not identified any non-compliance with regulations and/or voluntary codes, a brief statement of this fact is sufficient.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-417-2", "GRI-417-2-2", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-418-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-418-1", "GRI-418-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-418-r2", "The reporting organization shall report the following information: a. Total number of substantiated complaints received concerning breaches of customer privacy, categorized by: complaints received from outside parties and substantiated by the organization; complaints from regulatory bodies. b. Total number of identified leaks, thefts, or losses of customer data. c. If the organization has not identified any substantiated complaints, a brief statement of this fact is sufficient.", NOW(), NOW(), NOW(), "SUBSTANTIATED_COMPLAINT, BREACH_OF_CUSTOMER_PRIVACY", "NaN", "DOCUMENT", "GRI-418-2", "GRI-418-2-1", "");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-419-r1", "The reporting organization shall report its management approach for economic performance using GRI 103: Management Approach.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-419-1", "GRI-419-1-0", "GRI-103-r1,GRI-103-r2,GRI-103-r3,GRI-103-r4");
INSERT INTO gri_requirement(Identifier, Description, Last_used, Last_updated, Time_created, Terms, ValueRange, Cardinality, Category_ID, Disclosure_ID, Requirement_Dependency) VALUES ("GRI-419-r2", "The reporting organization shall report the following information: a. Significant fines and non-monetary sanctions for non-compliance with laws and/or regulations in the social and economic area in terms of: total monetary value of significant fines; total number of non-monetary sanctions; cases brought through dispute resolution mechanisms. b. If the organization has not identified any non-compliance with laws and/or regulations, a brief statement of this fact is sufficient. c. The context against which significant fines and non-monetary sanctions were incurred.", NOW(), NOW(), NOW(), "", "NaN", "DOCUMENT", "GRI-419-2", "GRI-419-2-1", "");